23	/** Extract the element index (0-based) from a tupleElement call.
24	  * Supports both positional (1-based UInt64) and named (String) access.
25	  * Returns std::nullopt if not determinable at analysis time.
26	  */
27	std::optional<size_t> getTupleElementIndex(const ConstantNode & index_node, const Strings & attribute_names)
28	{
29	    Field value = index_node.getValue();
30	
31	    if (value.getType() == Field::Types::String)
32	    {
33	        /// Named access: dictGet returns a named tuple, so `.country` becomes tupleElement(..., 'country')
34	        const auto & name = value.safeGet<String>();
35	        for (size_t i = 0; i < attribute_names.size(); ++i)
36	        {
37	            if (attribute_names[i] == name)
38	                return i;
39	        }
40	        return std::nullopt;
41	    }
42	
43	    if (value.getType() == Field::Types::UInt64)
44	    {
45	        UInt64 idx = value.safeGet<UInt64>();
46	        if (idx >= 1 && idx <= attribute_names.size())
47	            return static_cast<size_t>(idx - 1);
48	    }
49	
50	    return std::nullopt;
51	}
