53	/** Try to extract attribute names from the second argument of dictGet/dictGetOrDefault.
54	  * Returns empty vector if not a constant tuple of strings.
55	  */
56	Strings extractAttributeNames(const QueryTreeNodePtr & arg)
57	{
58	    Strings result;
59	
60	    if (const auto * constant_node = arg->as<ConstantNode>())
61	    {
62	        Field value = constant_node->getValue();
63	
64	        if (value.getType() == Field::Types::Tuple)
65	        {
66	            const auto & tuple = value.safeGet<Tuple>();
67	            for (const auto & elem : tuple)
68	            {
69	                if (elem.getType() != Field::Types::String)
70	                    return {};
71	                result.push_back(elem.safeGet<String>());
72	            }
73	            return result;
74	        }
75	    }
76	    else if (const auto * function_node = arg->as<FunctionNode>())
77	    {
78	        if (function_node->getFunctionName() == "tuple")
79	        {
80	            for (const auto & child : function_node->getArguments().getNodes())
81	            {
82	                const auto * child_constant = child->as<ConstantNode>();
83	                if (!child_constant)
84	                    return {};
85	
86	                Field value = child_constant->getValue();
87	                if (value.getType() != Field::Types::String)
88	                    return {};
89	
90	                result.push_back(value.safeGet<String>());
91	            }
92	            return result;
93	        }
94	    }
95	
96	    return {};
97	}
