100	class DictGetTupleElementVisitor : public InDepthQueryTreeVisitorWithContext<DictGetTupleElementVisitor>
101	{
102	public:
103	    using Base = InDepthQueryTreeVisitorWithContext<DictGetTupleElementVisitor>;
104	    using Base::Base;
105	
106	    void enterImpl(QueryTreeNodePtr & node)
107	    {
108	        if (!getSettings()[Setting::optimize_dictget_tuple_element])
109	            return;
110	
111	        auto * tuple_element_function = node->as<FunctionNode>();
112	        if (!tuple_element_function || tuple_element_function->getFunctionName() != "tupleElement")
113	            return;
114	
115	        auto & tuple_element_args = tuple_element_function->getArguments().getNodes();
116	        if (tuple_element_args.size() != 2)
117	            return;
118	
119	        auto * dict_get_function = tuple_element_args[0]->as<FunctionNode>();
120	        if (!dict_get_function)
121	            return;
122	
123	        const auto & dict_get_name = dict_get_function->getFunctionName();
124	        bool is_dict_get = (dict_get_name == "dictGet");
125	        bool is_dict_get_or_default = (dict_get_name == "dictGetOrDefault");
126	
127	        if (!is_dict_get && !is_dict_get_or_default)
128	            return;
129	
130	        auto & dict_get_args = dict_get_function->getArguments().getNodes();
131	
132	        /// dictGet has at least 3 args: dict_name, attr_names, key_expr [, ...]
133	        /// dictGetOrDefault has at least 4: dict_name, attr_names, key_expr, default_value [, ...]
134	        if (dict_get_args.size() < 3)
135	            return;
136	
137	        /// Extract attribute names from the second argument
138	        Strings attribute_names = extractAttributeNames(dict_get_args[1]);
139	        if (attribute_names.size() < 2)
140	            return;
141	
142	        /// Get the tuple element index
143	        const auto * index_node = tuple_element_args[1]->as<ConstantNode>();
144	        if (!index_node)
145	            return;
146	
147	        auto maybe_index = getTupleElementIndex(*index_node, attribute_names);
148	        if (!maybe_index)
149	            return;
150	
151	        size_t element_index = *maybe_index;
152	
153	        /// Prepare the new attribute name argument
154	        auto new_attr_arg = std::make_shared<ConstantNode>(attribute_names[element_index]);
155	
156	        /// For dictGetOrDefault, prepare the new default value argument before mutating anything.
157	        /// If we can't extract it, bail out without touching the tree.
158	        QueryTreeNodePtr new_default_arg;
159	        if (is_dict_get_or_default)
160	        {
161	            size_t default_arg_idx = dict_get_args.size() - 1;
162	            const auto & default_arg = dict_get_args[default_arg_idx];
163	
164	            /// `dictGetOrDefault` casts the entire default tuple to the dict's attribute tuple type at
165	            /// execution (see `castColumnAccurate` in `FunctionDictGetNoType::executeImpl`). If the
166	            /// element types of the default tuple don't match the dict's attribute types, that cast
167	            /// can throw on an un-selected element (for example, a string default for a `UInt64`
168	            /// attribute). After rewriting to a single-attribute call only the selected element is
169	            /// cast, so such exceptions are suppressed. Bail out unless element types match exactly
170	            /// (names may differ — they don't affect cast semantics).
171	            const auto * default_tuple_type = typeid_cast<const DataTypeTuple *>(default_arg->getResultType().get());
172	            const auto * result_tuple_type = typeid_cast<const DataTypeTuple *>(dict_get_function->getResultType().get());
173	            if (!default_tuple_type || !result_tuple_type)
174	                return;
175	
176	            const auto & default_elems = default_tuple_type->getElements();
177	            const auto & result_elems = result_tuple_type->getElements();
178	            if (default_elems.size() != result_elems.size())
179	                return;
180	            for (size_t i = 0; i < default_elems.size(); ++i)
181	                if (!default_elems[i]->equals(*result_elems[i]))
182	                    return;
183	
184	            if (const auto * default_constant = default_arg->as<ConstantNode>())
185	            {
186	                Field default_value = default_constant->getValue();
187	                if (default_value.getType() == Field::Types::Tuple)
188	                {
189	                    const auto & default_tuple = default_value.safeGet<Tuple>();
190	                    if (element_index < default_tuple.size())
191	                        new_default_arg = std::make_shared<ConstantNode>(default_tuple[element_index]);
192	                    else
193	                        return; /// Cannot optimize — index out of range
194	                }
195	            }
196	            else if (const auto * default_function = default_arg->as<FunctionNode>())
197	            {
198	                if (default_function->getFunctionName() == "tuple")
199	                {
200	                    const auto & default_tuple_args = default_function->getArguments().getNodes();
201	                    if (element_index >= default_tuple_args.size())
202	                        return; /// Cannot optimize — index out of range
203	
204	                    /// Only rewrite when all tuple arguments are constants. Otherwise, dropping the
205	                    /// other elements could lose side effects (e.g. `tuple('ok', throwIf(1))` would
206	                    /// no longer evaluate `throwIf(1)` after the rewrite, changing query semantics).
207	                    bool all_constants = true;
208	                    for (const auto & tuple_arg : default_tuple_args)
209	                    {
210	                        if (!tuple_arg->as<ConstantNode>())
211	                        {
212	                            all_constants = false;
213	                            break;
214	                        }
215	                    }
216	
217	                    if (all_constants)
218	                        new_default_arg = default_tuple_args[element_index];
219	                }
220	            }
221	        }
222	
223	        /// For dictGetOrDefault, both pieces must be rewritable — bail out if not
224	        if (is_dict_get_or_default && !new_default_arg)
225	            return;
226	
227	        /// The outer tupleElement node (and hence its child dictGet) may be shared across
228	        /// multiple parents — e.g. ORDER BY ALL referencing SELECT expressions. Mutating
229	        /// dict_get_function in place would change its return type from Tuple to a scalar,
230	        /// leaving the other parent's tupleElement wrapping a now-scalar dictGet. Clone
231	        /// the dictGet so the original remains intact for any other parents.
232	        auto new_dict_get_node = dict_get_function->clone();
233	        auto & new_dict_get_function = new_dict_get_node->as<FunctionNode &>();
234	        auto & new_dict_get_args = new_dict_get_function.getArguments().getNodes();
235	
236	        new_dict_get_args[1] = std::move(new_attr_arg);
237	
238	        if (new_default_arg)
239	        {
240	            size_t default_arg_idx = new_dict_get_args.size() - 1;
241	            new_dict_get_args[default_arg_idx] = std::move(new_default_arg);
242	        }
243	
244	        resolveOrdinaryFunctionNodeByName(new_dict_get_function, dict_get_name, getContext());
245	
246	        /// The single-attribute form of `dictGet` preserves a `LowCardinality` wrapper from the
247	        /// key argument, while the tuple-attribute form drops it (a tuple cannot be `LowCardinality`).
248	        /// If the result types differ, the rewrite would change the type observed by the parent
249	        /// node and break the surrounding query tree. Bail out in that case.
250	        if (!new_dict_get_function.getResultType()->equals(*tuple_element_function->getResultType()))
251	            return;
252	
253	        node = std::move(new_dict_get_node);
254	    }
255	};
256	
